local AutoWorkAdverts = {} ---自动锻炼广告

local function sortAdverts(adverts)
    table.sort(adverts, function(a, b)
        return a.id < b.id
    end)
end

local function getAutoWorkAdvert(id)
    for _, advert in pairs(AutoWorkAdverts) do
        if advert.id == id then
            return advert
        end
    end
end

local function countAdvertNum(oneAdvert)
    local count = 1
    for _, advert in pairs(AutoWorkAdverts) do
        local nextAdvert = getAutoWorkAdvert(oneAdvert.nextId)
        if nextAdvert then
            count = count + 1
            oneAdvert = nextAdvert
        end
    end
    return count
end

local function canAutoWorkReward(player)
    local recordId = player.advertInfo.records[tostring(Define.AdType.AutoWork)]
    if not recordId then
        return true
    end
    local config = getAutoWorkAdvert(recordId)
    return config.nextId ~= 0
end

local function doAutoWorkAdReward(player, id)
    local advert = getAutoWorkAdvert(id)
    if not advert then
        return
    end

    if not canAutoWorkReward(player) then
        return
    end

    player.advertInfo.records[tostring(Define.AdType.AutoWork)] = id

    player.property.advAutoWork = true

    ReportUtil.reportAutoWorkAdReward(player)

    local key = LuaTimer:schedule(function(userId)
        local c_player = PlayerManager:getPlayerByUserId(userId)
        if not c_player then
            return
        end
        ---返回之前的位置
        c_player:teleportBackAutoWork()
        c_player.property.advAutoWork = false
    end, advert.duration * 1000, nil, player.userId)

    player.timerKeys[tostring(Define.AdType.AutoWork)] = key
    local nextAd = getAutoWorkAdvert(advert.nextId)
    if not nextAd then
        GamePacketSender:sendAutoWorkAdInfo(player.rakssid, 0, 0, advert.duration, 0,0)
    else
        local count = countAdvertNum(nextAd)
        GamePacketSender:sendAutoWorkAdInfo(player.rakssid, nextAd.type, nextAd.id, advert.duration, advert.waitTime, count)
    end
end



AdvertConfig = {}

function AdvertConfig:init(config)
    for _, advert in pairs(config) do
        local item = {
            id = tonumber(advert.id),
            type = tonumber(advert.type),
            duration = tonumber(advert.duration),
            waitTime = tonumber(advert.waitTime),
            nextId = tonumber(advert.nextId)
        }
        if item.type == Define.AdType.AutoWork then
            table.insert(AutoWorkAdverts, item)
        end
    end
    sortAdverts(AutoWorkAdverts)
end

function AdvertConfig:initPlayerAdvert(player)
    local info = player.advertInfo
    local dayKey = DateUtil.getYearDay()
    if info.dayKey ~= dayKey then
        info.dayKey = dayKey
        info.records = {}
    end
    if player.property.payItemList[tostring(Define.PayItemType.AutoWorkout)] == nil then
        ---玩家没有购买自动锻炼，上线查找下一个自动锻炼的广告
        local autoWorkId
        local recordId = info.records[tostring(Define.AdType.AutoWork)]
        if not recordId then
            if #AutoWorkAdverts ~= 0 then
                autoWorkId = AutoWorkAdverts[1].id
            end
        else
            local config = getAutoWorkAdvert(recordId)
            if config then
                autoWorkId = config.nextId
            end
        end
        if autoWorkId then
            local config = getAutoWorkAdvert(autoWorkId)
            if config then
                ---查找到有广告
                local count = countAdvertNum(config)
                GamePacketSender:sendAutoWorkAdInfo(player.rakssid, config.type, config.id, 0, 0, count)
            end
        end
    end
end

function AdvertConfig:doAdvertReward(player, type, id)
    if type == Define.AdType.AutoWork then
        doAutoWorkAdReward(player, id)
        return
    end
end

--玩家看完广告进入自动锻炼区后、退出自动锻炼区
function AdvertConfig:backAutoWork(player)

    if player.property.payItemList[tostring(Define.PayItemType.AutoWorkout)] == nil then

        local id = player.advertInfo.records[tostring(Define.AdType.AutoWork)]

        local advert = getAutoWorkAdvert(id)
        if not advert then
            return
        end

        local nextAd = getAutoWorkAdvert(advert.nextId)
        if not nextAd then
            GamePacketSender:sendAutoWorkAdInfo(player.rakssid, 0, 0, 0, 0,0)
        else
            local count = countAdvertNum(nextAd)
            GamePacketSender:sendAutoWorkAdInfo(player.rakssid, nextAd.type, nextAd.id,0, advert.waitTime, count)
        end

        --self.workoutAdInfo.duration = 0
        LuaTimer:cancel(player.timerKeys[tostring(Define.AdType.AutoWork)])

        player.property.advAutoWork = false

    end
end